  1→import { Suspense, lazy, useState, useEffect, useRef } from 'react';
  2→import { Navigate, Outlet, Route, Routes, useNavigate } from 'react-router-dom';
  3→import { Search } from 'lucide-react';
  4→import { AuthGuard } from './components/auth/AuthGuard';
  5→import { AppLayout } from './components/layout/AppLayout';
  6→import { AuthProvider, useAuth } from './hooks/useAuth';
  7→
  8→import AuthPage from './pages/AuthPage';
  9→import SectorSelectPage from './pages/SectorSelectPage';
 10→const RadarPage = lazy(() => import('./pages/RadarPage'));
 11→const ProspectDetailPage = lazy(() => import('./pages/ProspectDetailPage'));
 12→const PipelinePage = lazy(() => import('./pages/PipelinePage'));
 13→const SourcesPage = lazy(() => import('./pages/SourcesPage'));
 14→const StatsPage = lazy(() => import('./pages/StatsPage'));
 15→const SettingsPage = lazy(() => import('./pages/SettingsPage'));
 16→
 17→const LoadingScreen = (): JSX.Element => (
 18→  <div className="flex min-h-screen items-center justify-center bg-leadradar-bg">
 19→    <div className="h-12 w-12 animate-spin rounded-full border-4 border-leadradar-border border-t-leadradar-accent" />
 20→  </div>
 21→);
 22→
 23→const ProtectedShell = (): JSX.Element => (
 24→  <AuthGuard>
 25→    <AppLayout>
 26→      <Outlet />
 27→    </AppLayout>
 28→  </AuthGuard>
 29→);
 30→
 31→const CommandPalette: React.FC<{ isOpen: boolean; onClose: () => void; onNavigate: (view: string) => void; }> = ({ isOpen, onClose, onNavigate }) => {
 32→  const [query, setQuery] = useState('');
 33→  const inputRef = useRef<HTMLInputElement>(null);
 34→
 35→  useEffect(() => {
 36→    if (isOpen) {
 37→      setTimeout(() => inputRef.current?.focus(), 100);
 38→      setQuery('');
 39→    }
 40→  }, [isOpen]);
 41→
 42→  const commands = [
 43→    { id: 'analyze', label: 'Nouvel Audit AEO', icon: '\u{1F50D}', category: 'Navigation' },
 44→    { id: 'dashboard', label: 'Dashboard Pro', icon: '\u{1F4CA}', category: 'Navigation' },
 45→    { id: 'projects', label: 'Monitoring AEO', icon: '\u{1F4C8}', category: 'Navigation' },
 46→    { id: 'generative-tools', label: 'Outils G\u00e9n\u00e9ratifs', icon: '\u2728', category: 'Outils' },
 47→    { id: 'smc-studio', label: 'SMC Studio', icon: '\u270F\uFE0F', category: 'Outils' },
 48→    { id: 'content-writer', label: 'AI Content Writer', icon: '\u{1F4DD}', category: 'Outils' },
 49→    { id: 'reputation', label: 'R\u00e9putation IA', icon: '\u{1F6E1}\uFE0F', category: 'Outils' },
 50→    { id: 'source-of-truth', label: 'Source of Truth', icon: '\u{1F4C4}', category: 'Outils' },
 51→    { id: 'schema-org', label: 'Schema.org Generator', icon: '\u{1F527}', category: 'Outils' },
 52→    { id: 'robots-txt', label: 'Robots.txt Optimizer', icon: '\u{1F916}', category: 'Outils' },
 53→    { id: 'bot-tracking', label: 'Suivi Bots IA', icon: '\u{1F441}\uFE0F', category: 'Outils' },
 54→    { id: 'blog-optimizer', label: 'Blog Optimiser', icon: '\u{1F4F0}', category: 'Outils' },
 55→    { id: 'directory', label: 'Annuaire Index\u00e9', icon: '\u{1F4DA}', category: 'Navigation' },
 56→    { id: 'recharge', label: 'GTO Gas Station', icon: '\u26FD', category: 'Navigation' },
 57→    { id: 'clients', label: 'Base Clients', icon: '\u{1F465}', category: 'Navigation' },
 58→    { id: 'mission-orders', label: 'Ordres de Mission', icon: '\u{1F4CB}', category: 'Navigation' },
 59→    { id: 'alerts', label: 'Alertes AEO', icon: '\u{1F514}', category: 'Navigation' },
 60→    { id: 'account', label: 'Compte & Plan', icon: '\u{1F464}', category: 'Navigation' },
 61→    { id: 'affiliation', label: 'Programme Partenaire', icon: '\u{1F91D}', category: 'Navigation' },
 62→  ];
 63→
 64→  const filtered = query
 65→    ? commands.filter(c => c.label.toLowerCase().includes(query.toLowerCase()))
 66→    : commands;
 67→
 68→  const grouped = filtered.reduce((acc, cmd) => {
 69→    if (!acc[cmd.category]) acc[cmd.category] = [];
 70→    acc[cmd.category].push(cmd);
 71→    return acc;
 72→  }, {} as Record<string, typeof commands>);
 73→
 74→  if (!isOpen) return null;
 75→
 76→  return (
 77→    <div className="fixed inset-0 z-[100] flex items-start justify-center pt-[20vh]" onClick={onClose}>
 78→      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" />
 79→      <div
 80→        className="relative w-full max-w-[560px] bg-[#13131d] border border-white/[0.1] rounded-2xl shadow-2xl shadow-black/50 overflow-hidden animate-in fade-in zoom-in-95 duration-200"
 81→        onClick={(e) => e.stopPropagation()}
 82→      >
 83→        {/* Search Input */}
 84→        <div className="flex items-center gap-3 px-5 py-4 border-b border-white/[0.08]">
 85→          <Search size={18} className="text-gray-500 shrink-0" />
 86→          <input
 87→            ref={inputRef}
 88→            type="text"
 89→            value={query}
 90→            onChange={(e) => setQuery(e.target.value)}
 91→            placeholder="Rechercher une page, un outil..."
 92→            className="flex-1 bg-transparent text-white text-[15px] placeholder-gray-600 outline-none"
 93→          />
 94→          <kbd className="hidden sm:flex items-center gap-1 px-2 py-0.5 text-[10px] text-gray-600 bg-white/[0.04] border border-white/[0.08] rounded-md font-mono">
 95→            ESC
 96→          </kbd>
 97→        </div>
 98→
 99→        {/* Results */}
100→        <div className="max-h-[340px] overflow-y-auto py-2 custom-scrollbar">
101→          {Object.keys(grouped).length === 0 ? (
102→            <div className="px-5 py-8 text-center text-gray-600 text-sm">Aucun r{'\u00e9'}sultat pour {'\u201C'}{query}{'\u201D'}</div>
103→          ) : (
104→            Object.entries(grouped).map(([category, cmds]) => (
105→              <div key={category}>
106→                <div className="px-5 py-2 text-[10px] font-bold text-gray-600 uppercase tracking-wider">{category}</div>
107→                {cmds.map((cmd) => (
108→                  <button
109→                    key={cmd.id}
110→                    onClick={() => { onNavigate(cmd.id); onClose(); }}
111→                    className="w-full flex items-center gap-3 px-5 py-2.5 text-left hover:bg-white/[0.04] transition-colors group"
112→                  >
113→                    <span className="text-base">{cmd.icon}</span>
114→                    <span className="text-[14px] text-gray-300 group-hover:text-white transition-colors">{cmd.label}</span>
115→                  </button>
116→                ))}
117→              </div>
118→            ))
119→          )}
120→        </div>
121→
122→        {/* Footer */}
123→        <div className="px-5 py-3 border-t border-white/[0.06] flex items-center justify-between text-[11px] text-gray-600">
124→          <div className="flex items-center gap-3">
125→            <span className="flex items-center gap-1"><kbd className="px-1.5 py-0.5 bg-white/[0.04] border border-white/[0.08] rounded text-[10px] font-mono">{'\u2191\u2193'}</kbd> naviguer</span>
126→            <span className="flex items-center gap-1"><kbd className="px-1.5 py-0.5 bg-white/[0.04] border border-white/[0.08] rounded text-[10px] font-mono">{'\u21B5'}</kbd> ouvrir</span>
127→          </div>
128→          <span>CitedBy.ai</span>
129→        </div>
130→      </div>
131→    </div>
132→  );
133→};
134→
135→const AppContent = (): JSX.Element => {
136→  const { user } = useAuth();
137→  const navigate = useNavigate();
138→  const [isCommandPaletteOpen, setIsCommandPaletteOpen] = useState(false);
139→
140→  useEffect(() => {
141→    const handleKeyDown = (e: KeyboardEvent) => {
142→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
143→        e.preventDefault();
144→        setIsCommandPaletteOpen(prev => !prev);
145→      }
146→      if (e.key === 'Escape') {
147→        setIsCommandPaletteOpen(false);
148→      }
149→    };
150→    document.addEventListener('keydown', handleKeyDown);
151→    return () => document.removeEventListener('keydown', handleKeyDown);
152→  }, []);
153→
154→  const navigateTo = (view: string) => {
155→    navigate('/' + view);
156→  };
157→
158→  return (
159→    <Suspense fallback={<LoadingScreen />}>
160→      {user && <CommandPalette isOpen={isCommandPaletteOpen} onClose={() => setIsCommandPaletteOpen(false)} onNavigate={(view) => navigateTo(view)} />}
161→      <Routes>
162→        <Route path="/auth" element={<AuthPage />} />
163→        <Route path="/onboarding/sector" element={<SectorSelectPage />} />
164→        <Route element={<ProtectedShell />}>
165→          <Route index element={<Navigate replace to="/radar" />} />
166→          <Route path="/radar" element={<RadarPage />} />
167→          <Route path="/prospect/:id" element={<ProspectDetailPage />} />
168→          <Route path="/pipeline" element={<PipelinePage />} />
169→          <Route path="/sources" element={<SourcesPage />} />
170→          <Route path="/statistiques" element={<StatsPage />} />
171→          <Route path="/reglages" element={<SettingsPage />} />
172→        </Route>
173→        <Route path="*" element={<Navigate replace to="/radar" />} />
174→      </Routes>
175→    </Suspense>
176→  );
177→};
178→
179→const App = (): JSX.Element => (
180→  <AuthProvider>
181→    <AppContent />
182→  </AuthProvider>
183→);
184→
185→export default App;
186→

  1→import { useEffect, useMemo, useRef, useState } from 'react';
  2→import { useNavigate } from 'react-router-dom';
  3→import { HeatBadge } from '../components/shared/HeatBadge';
  4→import { ScoreRing } from '../components/shared/ScoreRing';
  5→import { useProspects } from '../hooks/useProspects';
  6→import { getSectorUiMeta } from '../lib/constants';
  7→import type { HeatLevel } from '../lib/types';
  8→import { useAuth } from '../hooks/useAuth';
  9→import { getProfileSectorTargets } from '../utils/sector-targeting';
 10→import { formatRelativeDate } from '../utils/format';
 11→import { getProspectImageUrl } from '../utils/prospect-media';
 12→
 13→type RadarFilter = 'all' | HeatLevel;
 14→
 15→const FILTERS: Array<{ key: RadarFilter; label: string }> = [
 16→  { key: 'all', label: 'Tous' },
 17→  { key: 'burning', label: 'Brulants' },
 18→  { key: 'hot', label: 'Chauds' },
 19→  { key: 'warm', label: 'Tiedes' },
 20→];
 21→
 22→/**
 23→ * Skeleton d'une carte prospect.
 24→ */
 25→const ProspectCardSkeleton = (): JSX.Element => (
 26→  <div className="animate-pulse rounded-xl border border-leadradar-border bg-leadradar-card p-4">
 27→    <div className="mb-3 h-4 w-1/3 rounded bg-slate-700/60" />
 28→    <div className="mb-2 h-6 w-2/3 rounded bg-slate-700/60" />
 29→    <div className="h-4 w-full rounded bg-slate-700/50" />
 30→  </div>
 31→);
 32→
 33→/**
 34→ * Vue principale Radar.
 35→ */
 36→const RadarPage = (): JSX.Element => {
 37→  const navigate = useNavigate();
 38→  const { profile } = useAuth();
 39→  const [filter, setFilter] = useState<RadarFilter>('all');
 40→  const { prospects, counters, loading, loadingMore, error, fetchMore, hasMore, newProspectIds } = useProspects(filter);
 41→  const loadMoreRef = useRef<HTMLDivElement | null>(null);
 42→  const primaryTarget = getProfileSectorTargets(profile)[0];
 43→  const sectorColor = getSectorUiMeta(primaryTarget?.id, primaryTarget?.label).color;
 44→  const missingCredits = (profile?.credits_balance ?? 0) <= 0;
 45→  const missingZone = !profile?.location_label;
 46→
 47→  const monthTotal = useMemo(() => counters.total, [counters.total]);
 48→
 49→  useEffect(() => {
 50→    if (!hasMore) {
 51→      return;
 52→    }
 53→    const target = loadMoreRef.current;
 54→    if (!target) {
 55→      return;
 56→    }
 57→    const observer = new IntersectionObserver(
 58→      (entries) => {
 59→        entries.forEach((entry) => {
 60→          if (entry.isIntersecting) {
 61→            void fetchMore();
 62→          }
 63→        });
 64→      },
 65→      { rootMargin: '120px' },
 66→    );
 67→    observer.observe(target);
 68→    return () => observer.disconnect();
 69→  }, [fetchMore, hasMore]);
 70→
 71→  return (
 72→    <div className="space-y-6 px-4 md:px-0">
 73→      <header className="flex flex-col gap-2 md:flex-row md:items-center md:justify-between">
 74→        <div>
 75→          <h1 className="font-outfit text-3xl font-bold">Radar des prospects</h1>
 76→          <p className="text-sm text-slate-300">Liste simple des opportunites detectees dans votre secteur.</p>
 77→        </div>
 78→        <div className="inline-flex items-center gap-2 rounded-full border border-emerald-500/25 bg-emerald-500/10 px-3 py-1 text-sm text-emerald-300">
 79→          <span className="h-2.5 w-2.5 animate-pulse-live rounded-full bg-emerald-400" />
 80→          En direct
 81→        </div>
 82→      </header>
 83→
 84→      {missingCredits || missingZone ? (
 85→        <section className="rounded-xl border border-amber-500/30 bg-amber-500/10 p-4">
 86→          <h2 className="font-outfit text-lg font-semibold text-amber-200">Demarrage rapide</h2>
 87→          <p className="mt-1 text-sm text-amber-100">
 88→            Parcours conseille: recharge credits puis configuration zone avant de traiter les prospects.
 89→          </p>
 90→          <div className="mt-3 flex flex-wrap gap-2 text-xs">
 91→            <span
 92→              className={`rounded-full px-2 py-1 ${
 93→                missingCredits ? 'bg-amber-600/30 text-amber-100' : 'bg-emerald-500/20 text-emerald-200'
 94→              }`}
 95→            >
 96→              {missingCredits ? '1. Credits a recharger' : '1. Credits OK'}
 97→            </span>
 98→            <span
 99→              className={`rounded-full px-2 py-1 ${
100→                missingZone ? 'bg-amber-600/30 text-amber-100' : 'bg-emerald-500/20 text-emerald-200'
101→              }`}
102→            >
103→              {missingZone ? '2. Zone a configurer' : '2. Zone OK'}
104→            </span>
105→          </div>
106→          <button
107→            type="button"
108→            onClick={() => navigate('/reglages')}
109→            className="mt-3 rounded-lg bg-emerald-500 px-3 py-2 text-sm font-semibold text-emerald-950"
110→          >
111→            Ouvrir la configuration
112→          </button>
113→        </section>
114→      ) : null}
115→
116→      <section className="grid grid-cols-2 gap-3 md:grid-cols-4">
117→        <article className="rounded-xl border border-leadradar-border bg-leadradar-card p-4">
118→          <p className="text-xs text-slate-400">Total detectes (mois)</p>
119→          <p className="mt-2 text-2xl font-bold">{monthTotal}</p>
120→        </article>
121→        <article className="rounded-xl border border-leadradar-border bg-leadradar-card p-4">
122→          <p className="text-xs text-slate-400">Brulants</p>
123→          <p className="mt-2 text-2xl font-bold text-red-400">{counters.burning}</p>
124→        </article>
125→        <article className="rounded-xl border border-leadradar-border bg-leadradar-card p-4">
126→          <p className="text-xs text-slate-400">Chauds</p>
127→          <p className="mt-2 text-2xl font-bold text-orange-300">{counters.hot}</p>
128→        </article>
129→        <article className="rounded-xl border border-leadradar-border bg-leadradar-card p-4">
130→          <p className="text-xs text-slate-400">Tiedes</p>
131→          <p className="mt-2 text-2xl font-bold text-amber-300">{counters.warm}</p>
132→        </article>
133→      </section>
134→
135→      <section className="flex flex-wrap gap-2">
136→        {FILTERS.map((option) => {
137→          const active = filter === option.key;
138→          return (
139→            <button
140→              key={option.key}
141→              type="button"
142→              onClick={() => setFilter(option.key)}
143→              className="rounded-full border px-4 py-1.5 text-sm transition"
144→              style={{
145→                borderColor: active ? sectorColor : '#1E293B',
146→                backgroundColor: active ? `${sectorColor}1E` : '#0F172A',
147→                color: active ? '#F8FAFC' : '#CBD5E1',
148→              }}
149→            >
150→              {option.label}
151→            </button>
152→          );
153→        })}
154→      </section>
155→
156→      {error ? (
157→        <div className="rounded-lg border border-red-500/40 bg-red-500/10 p-3 text-sm text-red-300">{error}</div>
158→      ) : null}
159→
160→      <section className="space-y-3">
161→        {loading
162→          ? Array.from({ length: 5 }).map((_, index) => <ProspectCardSkeleton key={`skeleton-${index}`} />)
163→          : prospects.map((prospect) => {
164→              const leftBorder =
165→                prospect.heat === 'burning'
166→                  ? '#EF4444'
167→                  : prospect.heat === 'hot'
168→                    ? '#F97316'
169→                    : prospect.heat === 'warm'
170→                      ? '#F59E0B'
171→                      : '#64748B';
172→              const isNew = newProspectIds.includes(prospect.id);
173→              const imageUrl = getProspectImageUrl(prospect.details_json, prospect.raw_data_json);
174→
175→              return (
176→                <button
177→                  key={prospect.id}
178→                  type="button"
179→                  onClick={() => navigate(`/prospect/${prospect.id}`)}
180→                  className={`w-full rounded-xl border border-leadradar-border bg-leadradar-card p-4 text-left transition hover:border-slate-500 ${
181→                    isNew ? 'animate-slide-in' : ''
182→                  }`}
183→                  style={{ borderLeft: `4px solid ${leftBorder}` }}
184→                >
185→                  <div className="flex flex-col gap-3 md:flex-row md:items-start md:justify-between">
186→                    <div className="flex items-start gap-3">
187→                      <ScoreRing score={prospect.score} />
188→                      <div className="space-y-2">
189→                        <div className="flex flex-wrap items-center gap-2">
190→                          <HeatBadge heat={prospect.heat} />
191→                          <span className="rounded-full border border-leadradar-border bg-[#0F172A] px-2 py-0.5 text-xs text-slate-300">
192→                            {prospect.source_icon ? `${prospect.source_icon} ` : ''}
193→                            {prospect.source_name ?? 'Source inconnue'}
194→                          </span>
195→                          <span className="text-xs text-slate-400">{formatRelativeDate(prospect.detected_at)}</span>
196→                        </div>
197→                        <h2 className="font-outfit text-xl font-semibold">{prospect.name}</h2>
198→                        <p className="text-sm text-slate-400">{prospect.location ?? 'Localisation non renseignee'}</p>
199→                        <p className="line-clamp-2 text-sm text-slate-200">Signal: {prospect.signal}</p>
200→                      </div>
201→                    </div>
202→                    {imageUrl ? (
203→                      <img
204→                        src={imageUrl}
205→                        alt={`Photo ${prospect.name}`}
206→                        className="hidden h-24 w-36 rounded-lg border border-leadradar-border object-cover md:block"
207→                        loading="lazy"
208→                      />
209→                    ) : null}
210→                  </div>
211→                </button>
212→              );
213→            })}
214→        {!loading && prospects.length === 0 ? (
215→          <div className="rounded-xl border border-dashed border-leadradar-border bg-[#0F172A] p-8 text-center text-slate-400">
216→            Aucun prospect pour ce filtre.
217→          </div>
218→        ) : null}
219→      </section>
220→
221→      <div ref={loadMoreRef} />
222→      {loadingMore ? (
223→        <div className="rounded-xl border border-leadradar-border bg-leadradar-card p-4 text-center text-sm text-slate-300">
224→          Chargement des prospects...
225→        </div>
226→      ) : null}
227→    </div>
228→  );
229→};
230→
231→export default RadarPage;
232→

  1→import { useCallback, useEffect, useMemo, useState } from 'react';
  2→import { Link } from 'react-router-dom';
  3→import { CreditPacks } from '../components/settings/credit-packs';
  4→import { SectorTargetingSelector } from '../components/shared/sector-targeting-selector';
  5→import { useAuth } from '../hooks/useAuth';
  6→import { CREDIT_PACKS } from '../lib/constants';
  7→import { isSupabaseConfigured, supabase } from '../lib/supabase';
  8→import type { ApproachTone, CreditPackId, Profile } from '../lib/types';
  9→import { buildProfileSectorPatch, getProfileSectorTargets } from '../utils/sector-targeting';
 10→import { debounce } from '../utils/debounce';
 11→
 12→const TONE_PREVIEWS: Record<ApproachTone, string> = {
 13→  professional: 'Approche structuree, orientee resultat et claire.',
 14→  friendly: 'Approche plus chaleureuse et conversationnelle.',
 15→  direct: 'Approche courte, rapide et orientee action.',
 16→};
 17→
 18→interface ScanNowResponse {
 19→  job_id?: string;
 20→  triggered_sources?: number;
 21→  failed_sources?: number;
 22→  fallback_direct_ingest?: number;
 23→  used_n8n?: boolean;
 24→}
 25→
 26→/**
 27→ * Configuration utilisateur simplifiee.
 28→ */
 29→const SettingsPage = (): JSX.Element => {
 30→  const { profile, patchProfile, refreshProfile } = useAuth();
 31→  const [draft, setDraft] = useState<Profile | null>(profile);
 32→  const [error, setError] = useState<string | null>(null);
 33→  const [status, setStatus] = useState<string>('');
 34→  const [scanLoading, setScanLoading] = useState<boolean>(false);
 35→  const [scanFeedback, setScanFeedback] = useState<string>('');
 36→  const [scanError, setScanError] = useState<string | null>(null);
 37→  const [locationModalOpen, setLocationModalOpen] = useState<boolean>(false);
 38→  const [locationDraft, setLocationDraft] = useState<string>('');
 39→  const [radiusDraft, setRadiusDraft] = useState<number>(30);
 40→
 41→  useEffect(() => {
 42→    setDraft(profile);
 43→  }, [profile]);
 44→
 45→  const savePatch = useCallback(
 46→    async (patch: Partial<Profile>): Promise<void> => {
 47→      if (!profile) {
 48→        return;
 49→      }
 50→      setStatus('Sauvegarde...');
 51→      const ok = await patchProfile(patch);
 52→      if (!ok) {
 53→        setError('Erreur de sauvegarde.');
 54→        setStatus('');
 55→        return;
 56→      }
 57→      setError(null);
 58→      setStatus('Sauvegarde');
 59→      window.setTimeout(() => setStatus(''), 900);
 60→    },
 61→    [patchProfile, profile],
 62→  );
 63→
 64→  const debouncedSave = useMemo(
 65→    () =>
 66→      debounce((patch: Partial<Profile>) => {
 67→        void savePatch(patch);
 68→      }, 500),
 69→    [savePatch],
 70→  );
 71→
 72→  if (!draft || !profile) {
 73→    return (
 74→      <div className="px-4 md:px-0">
 75→        <div className="h-24 animate-pulse rounded-2xl border border-leadradar-border bg-leadradar-card" />
 76→      </div>
 77→    );
 78→  }
 79→
 80→  const creditsBalance = Number(draft.credits_balance ?? 0);
