13→export const CreditPacks = ({ userId }: CreditPacksProps): JSX.Element => {
14→  const [loadingPackId, setLoadingPackId] = useState<string | null>(null);
15→  const [error, setError] = useState<string | null>(null);
16→
17→  /**
18→   * Lance un checkout Stripe pour un pack de credits.
19→   */
20→  const buyPack = async (packId: string): Promise<void> => {
21→    if (!isSupabaseConfigured) {
22→      setError('Mode demo: achat de credits indisponible sans configuration Supabase.');
23→      return;
24→    }
25→    try {
26→      setLoadingPackId(packId);
27→      setError(null);
28→      const { data, error: invokeError } = await supabase.functions.invoke('create-checkout', {
29→        body: {
30→          user_id: userId,
31→          pack_id: packId,
32→        },
33→      });
34→      if (invokeError) {
35→        throw invokeError;
36→      }
37→      const checkoutUrl = String((data as { url?: string } | null)?.url ?? '');
38→      if (!checkoutUrl) {
39→        throw new Error('URL checkout manquante');
40→      }
41→      window.location.href = checkoutUrl;
42→    } catch (caughtError) {
43→      const message = caughtError instanceof Error ? caughtError.message : 'Achat credits impossible';
44→      setError(message);
45→    } finally {
46→      setLoadingPackId(null);
47→    }
48→  };
49→
50→  return (
51→    <section className="space-y-3">
52→      <div className="grid grid-cols-1 gap-3 md:grid-cols-2 xl:grid-cols-4">
53→        {CREDIT_PACKS.map((pack) => {
54→          const totalCredits = pack.credits + pack.bonusCredits;
55→          return (
56→            <article
57→              key={pack.id}
58→              className={`rounded-xl border p-4 ${
59→                pack.highlight ? 'border-emerald-500/50 bg-emerald-500/8' : 'border-leadradar-border bg-[#0F172A]'
60→              }`}
61→            >
62→              <div className="flex items-center justify-between">
63→                <h4 className="font-outfit text-lg font-semibold">{pack.label}</h4>
64→                {pack.bonusCredits > 0 ? (
65→                  <span className="rounded-full bg-emerald-500/15 px-2 py-0.5 text-[11px] text-emerald-300">
66→                    +{pack.bonusCredits} bonus
67→                  </span>
68→                ) : null}
69→              </div>
70→              <p className="mt-1 text-sm text-slate-300">{formatCurrency(pack.priceEur)}</p>
71→              <p className="mt-2 text-2xl font-bold text-emerald-300">{totalCredits} credits</p>
72→              <p className="text-xs text-slate-400">
73→                Base: {pack.credits}
74→                {pack.bonusCredits > 0 ? ` + Bonus: ${pack.bonusCredits}` : ''}
75→              </p>
76→              <p className="mt-1 text-xs text-slate-400">
77→                Cout par credit: {formatCurrency(pack.priceEur / totalCredits)}
78→              </p>
79→              <button
80→                type="button"
81→                disabled={loadingPackId !== null}
82→                onClick={() => {
83→                  void buyPack(pack.id);
84→                }}
85→                className="mt-4 w-full rounded-lg bg-emerald-500 px-3 py-2 text-sm font-semibold text-emerald-950 disabled:cursor-not-allowed disabled:opacity-60"
86→              >
87→                {loadingPackId === pack.id ? 'Chargement...' : 'Acheter ce pack'}
88→              </button>
89→            </article>
90→          );
91→        })}
92→      </div>
93→      {error ? <p className="text-sm text-red-400">{error}</p> : null}
94→    </section>
95→  );
96→};
